// ESP32-S3 sendet: {"ButtonN":{"Action":"SINGLE|DOUBLE|TRIPLE|HOLD"}}
var data = msg.payload;
var button = null;
var action = null;

for (var i = 1; i <= 5; i++) {
    var key = "Button" + i;
    if (data[key]) {
        button = i;
        action = data[key].Action;
        break;
    }
}

if (!button) {
    node.warn("Unbekanntes Payload: " + JSON.stringify(data));
    return null;
}

// Button-Namen
var names = {
    1: "Taste 1 (GPIO42)",
    2: "Taste 2 (GPIO41)",
    3: "Taste 3 (GPIO40)",
    4: "Funk 1 (RF)",
    5: "Funk 2 (RF)"
};

msg.button = button;
msg.action = action;
msg.buttonName = names[button];

// input_select Entity-ID bestimmen
var map = {
    "1_SINGLE": "input_select.wifibutton1_button1_single_action",
    "1_DOUBLE": "input_select.wifibutton1_button1_double_action",
    "1_TRIPLE": "input_select.wifibutton1_button1_triple_action",
    "2_SINGLE": "input_select.wifibutton1_button2_single_action",
    "2_DOUBLE": "input_select.wifibutton1_button2_double_action",
    "2_TRIPLE": "input_select.wifibutton1_button2_triple_action",
    "3_SINGLE": "input_select.wifibutton1_button3_single_action",
    "3_DOUBLE": "input_select.wifibutton1_button3_double_action",
    "3_TRIPLE": "input_select.wifibutton1_button3_triple_action",
    "4_SINGLE": "input_select.wifibutton1_funk1_action",
    "5_SINGLE": "input_select.wifibutton1_funk2_action"
};

var key = button + "_" + action;
msg.entity_id = map[key];

if (!msg.entity_id) {
    node.warn("Keine Zuordnung: " + key);
    node.status({fill:"yellow", shape:"ring", text: names[button] + " " + action + " (nicht zugeordnet)"});
    return null;
}

node.status({fill:"blue", shape:"dot", text: names[button] + " " + action});
msg.topic = names[button] + " " + action;
return msg;

// Gewaehlte Aktion aus input_select
var selectedAction = msg.selected_action || msg.payload;

// Mapping: Dropdown-Wert -> HA Script Entity
var scriptMap = {
    "Licht WZ Toggle":           "script.wifibtn_licht_wz_toggle",
    "Bad Licht An":              "script.wifibtn_bad_licht_an",
    "Bad Licht Aus":             "script.wifibtn_bad_licht_aus",
    "WLED An":                   "script.wifibtn_wled_an",
    "WLED Aus":                  "script.wifibtn_wled_aus",
    "Alexa Bad Radio Bayern 1":  "script.wifibtn_alexa_bad_radio_bayern1",
    "Alexa Bad Radio NDR2":      "script.wifibtn_alexa_bad_radio_ndr2",
    "Alexa Bad Radio Aus":       "script.wifibtn_alexa_bad_radio_aus",
    "Alexa Bad Spotify":         "script.wifibtn_alexa_bad_spotify",
    "Szene Alles Aus":           "script.wifibtn_szene_alles_aus",
    "Szene Gute Nacht":          "script.wifibtn_szene_gute_nacht",
    "Szene Film":                "script.wifibtn_szene_film",
    "Alexa Movie Radio":         "script.wifibtn_alexa_movie_radio",
    "Nichts":                    null
};

var script = scriptMap[selectedAction];

if (!script) {
    if (selectedAction !== "Nichts") {
        node.warn("Unbekannte Aktion: " + selectedAction);
    }
    node.status({fill:"grey", shape:"ring", text: "Nichts"});
    return null;
}

msg.script_entity = script;
msg.payload = {
    domain: "script",
    service: "turn_on",
    target: {
        entity_id: [script]
    }
};

var info = msg.buttonName + " -> " + selectedAction;
node.status({fill:"green", shape:"dot", text: info});
msg.topic = info;
return msg;

// Aktuelle Uhrzeit als HH:MM formatieren
var now = new Date();
var h = String(now.getHours()).padStart(2, '0');
var m = String(now.getMinutes()).padStart(2, '0');
msg.payload = h + ':' + m;
return msg;

// PV-Leistung formatieren
var watts = parseFloat(msg.payload) || 0;

if (watts >= 1000) {
    // Ab 1kW: '1.2kW' Format
    msg.payload = (watts / 1000).toFixed(1) + 'kW';
} else {
    // Unter 1kW: '420W' Format
    msg.payload = Math.round(watts) + 'W';
}

return msg;

// Tibber Preis-Status zu LED-Steuerung
// Status: günstig / normal / teuer
// Blinken: wenn binary_sensor.paule_best_price_period == on (08-22 Uhr)
// Peak: wenn binary_sensor.paule_peak_price_period == on -> Rot zusätzlich AN

var ha = global.get('homeassistant');
var states = (ha && ha.homeAssistant && ha.homeAssistant.states) || {};

function getState(id) {
    return states[id] ? states[id].state : '';
}

var status = getState('sensor.tibber_preis_status');
var bestPrice = getState('binary_sensor.paule_best_price_period');
var peakPrice = getState('binary_sensor.paule_peak_price_period');

// Zeitfenster 08:00 - 22:00 prüfen
var hour = new Date().getHours();
var inTimeWindow = (hour >= 8 && hour < 22);

// Blink-Modus: günstigste Periode UND im Zeitfenster
var shouldBlink = (bestPrice === 'on' && inTimeWindow);

// Peak-Modus: teuerste Periode aktiv -> Rot zusätzlich
var isPeak = (peakPrice === 'on');

var rot = "OFF";
var gelb = "OFF";
var gruen = "OFF";
var label = "?";

// ON oder BLINK je nach günstigster Periode
var onCmd = shouldBlink ? "BLINK" : "ON";

switch(status) {
    case "günstig":
        gruen = onCmd;
        label = "GRUEN" + (shouldBlink ? " ★BLINK★" : "");
        break;
    case "normal":
        gelb = onCmd;
        label = "GELB" + (shouldBlink ? " ★BLINK★" : "");
        break;
    case "teuer":
        rot = onCmd;
        label = "ROT" + (shouldBlink ? " ★BLINK★" : "");
        break;
    default:
        gelb = onCmd;
        label = "GELB (unbekannt: " + status + ")";
}

// Peak-Preisperiode: Rot IMMER zusätzlich einschalten (als Warnung)
if (isPeak && rot === "OFF") {
    rot = "ON";
    label += " +ROT(Peak)";
}

var fill = gruen !== "OFF" ? "green" : rot !== "OFF" ? "red" : "yellow";
var shape = shouldBlink ? "ring" : "dot";
node.status({fill: fill, shape: shape, text: label});

return [
    {payload: rot},
    {payload: gelb},
    {payload: gruen}
];

// Tibber Preis-Status zu LED-Steuerung
// Status: günstig / normal / teuer
// Blinken: wenn binary_sensor.paule_best_price_period == on (08-22 Uhr)
// Peak: wenn binary_sensor.paule_peak_price_period == on -> Rot zusätzlich AN

var ha = global.get('homeassistant');
var states = (ha && ha.homeAssistant && ha.homeAssistant.states) || {};

function getState(id) {
    return states[id] ? states[id].state : '';
}

var status = getState('sensor.tibber_preis_status');
var bestPrice = getState('binary_sensor.paule_best_price_period');
var peakPrice = getState('binary_sensor.paule_peak_price_period');

// Zeitfenster 08:00 - 22:00 prüfen
var hour = new Date().getHours();
var inTimeWindow = (hour >= 8 && hour < 22);

// Blink-Modus: günstigste Periode UND im Zeitfenster
var shouldBlink = (bestPrice === 'on' && inTimeWindow);

// Peak-Modus: teuerste Periode aktiv -> Rot zusätzlich
var isPeak = (peakPrice === 'on');

var rot = "OFF";
var gelb = "OFF";
var gruen = "OFF";
var label = "?";

// ON oder BLINK je nach günstigster Periode
var onCmd = shouldBlink ? "BLINK" : "ON";

switch(status) {
    case "günstig":
        gruen = onCmd;
        label = "GRUEN" + (shouldBlink ? " ★BLINK★" : "");
        break;
    case "normal":
        gelb = onCmd;
        label = "GELB" + (shouldBlink ? " ★BLINK★" : "");
        break;
    case "teuer":
        rot = onCmd;
        label = "ROT" + (shouldBlink ? " ★BLINK★" : "");
        break;
    default:
        gelb = onCmd;
        label = "GELB (unbekannt: " + status + ")";
}

// Peak-Preisperiode: Rot IMMER zusätzlich einschalten (als Warnung)
if (isPeak && rot === "OFF") {
    rot = "ON";
    label += " +ROT(Peak)";
}

var fill = gruen !== "OFF" ? "green" : rot !== "OFF" ? "red" : "yellow";
var shape = shouldBlink ? "ring" : "dot";
node.status({fill: fill, shape: shape, text: label});

return [
    {payload: rot},
    {payload: gelb},
    {payload: gruen}
];

var state = msg.payload; // "on" = window open, "off" = window closed

if (state === "on") {
    // Window OPENED - save current state and turn off
    // Read current TRV states from HA via previous state data
    var savedTemps = flow.get("sz_saved_temps") || {};
    // We save whatever was set before
    // Output: set both TRVs to "off" mode
    node.status({fill:"red", shape:"dot", text:"Fenster OFFEN - Heizung AUS"});

    return [
        {payload: {domain: "climate", service: "set_hvac_mode", target: {entity_id: ["climate.sz_heizung_links"]}, data: {hvac_mode: "off"}}},
        {payload: {domain: "climate", service: "set_hvac_mode", target: {entity_id: ["climate.sz_heizung_rechts"]}, data: {hvac_mode: "off"}}},
        {payload: "Fenster offen - Heizung AUS"}
    ];
} else if (state === "off") {
    // Window CLOSED - restore heating
    // Set both TRVs back to "heat" mode (they remember their target temp)
    node.status({fill:"green", shape:"dot", text:"Fenster ZU - Heizung freigegeben"});

    return [
        {payload: {domain: "climate", service: "set_hvac_mode", target: {entity_id: ["climate.sz_heizung_links"]}, data: {hvac_mode: "heat"}}},
        {payload: {domain: "climate", service: "set_hvac_mode", target: {entity_id: ["climate.sz_heizung_rechts"]}, data: {hvac_mode: "heat"}}},
        {payload: "Fenster zu - Heizung freigegeben"}
    ];
}

return [null, null, null];

var attrs = msg.attributes;
if (attrs && attrs.new_state && attrs.new_state.attributes) {
    var lp = parseFloat(attrs.new_state.attributes.last_period);
    if (!isNaN(lp)) {
        flow.set('m2_yesterday_kwh', lp);
    }
}

var watts = flow.get('m2_pv_watts') || 0;
var dailyKwh = flow.get('m2_daily_kwh') || 0;
var yesterdayKwh = flow.get('m2_yesterday_kwh') || 0;
var flashUntil = flow.get('m2_show_pv_until') || 0;
var now = Date.now();

// PV-Daten Phase (10s von 60s Zyklus)
if (now < flashUntil) {
    if (watts >= 15) {
        // Aktuelle Leistung in W
        msg.payload = Math.round(watts) + 'W';
    } else {
        // Tagessumme oder Vortag in kWh
        var kwh;
        if (dailyKwh < 0.05 && yesterdayKwh > 0.05) {
            kwh = yesterdayKwh;
        } else {
            kwh = dailyKwh;
        }
        // toFixed(1) mit Punkt - MAX7219 zeigt Punkt kompakt an
        msg.payload = kwh.toFixed(1) + 'kW';
    }
    return msg;
}

// Standard: Uhrzeit mit blinkendem Doppelpunkt
var d = new Date();
var h = String(d.getHours()).padStart(2, '0');
var m = String(d.getMinutes()).padStart(2, '0');
var sep = (d.getSeconds() % 2 === 0) ? ':' : ' ';
msg.payload = h + sep + m;
return msg;

// Flash fuer 10s aktivieren (Sekunde 50-60 im Zyklus)
flow.set('m2_show_pv_until', Date.now() + 10000);
// last_display zuruecksetzen damit sofort gesendet wird
flow.set('m2_last_display', '');

var hour = new Date().getHours();
if (hour >= 22 || hour < 7) {
    msg.payload = 1;  // Nacht: 10%
} else {
    msg.payload = 5;  // Tag: 33%
}
return msg;

var attrs = msg.attributes;
if (attrs && attrs.new_state && attrs.new_state.attributes) {
    var lp = parseFloat(attrs.new_state.attributes.last_period);
    if (!isNaN(lp)) {
        flow.set('m1_yesterday_kwh', lp);
    }
}

var watts = flow.get('m1_pv_watts') || 0;
var dailyKwh = flow.get('m1_daily_kwh') || 0;
var yesterdayKwh = flow.get('m1_yesterday_kwh') || 0;
var flashUntil = flow.get('m1_show_time_until') || 0;
var now = Date.now();

// Uhrzeit-Phase (10s von 60s Zyklus)
if (now < flashUntil) {
    var d = new Date();
    var h = String(d.getHours()).padStart(2, '0');
    var m = String(d.getMinutes()).padStart(2, '0');
    var sep = (d.getSeconds() % 2 === 0) ? ':' : ' ';
    msg.payload = h + sep + m;
    return msg;
}

// Standard: PV-Daten
if (watts >= 15) {
    msg.payload = Math.round(watts) + 'W';
} else {
    var kwh;
    if (dailyKwh < 0.05 && yesterdayKwh > 0.05) {
        kwh = yesterdayKwh;
    } else {
        kwh = dailyKwh;
    }
    msg.payload = kwh.toFixed(1) + 'kW';
}
return msg;

var hour = new Date().getHours();
if (hour >= 22 || hour < 7) {
    msg.payload = 1;
} else {
    msg.payload = 5;
}
return msg;

var attrs = msg.attributes;
if (attrs && attrs.new_state && attrs.new_state.attributes) {
    var lp = parseFloat(attrs.new_state.attributes.last_period);
    if (!isNaN(lp)) flow.set('m3_yesterday_kwh', lp);
}

// Sammle alle aktiven Alerts nach Prioritaet
// Max 4 Zeichen pro Alert (64px = 10 Zeichen total)
var alerts = [];
var ha = global.get('homeassistant');
if (!ha || !ha.homeAssistant || !ha.homeAssistant.states) {
    flow.set('m3_alerts', alerts);
    return null;
}
var states = ha.homeAssistant.states;

function getState(id) {
    return states[id] ? states[id].state : '';
}
function isOn(id) {
    return getState(id) === 'on';
}
function isEnabled(id) {
    return isOn('input_boolean.' + id);
}

// PRIO 1: KRITISCH
if (isEnabled('matrix3_thw_alarm') && isOn('binary_sensor.divera_alarm_aktiv')) {
    alerts.push('ALM!');
}
if (isEnabled('matrix3_internet_offline')) {
    var inet = getState('binary_sensor.fritz_box_6591_cable_vodafone_connection');
    if (inet === 'off') alerts.push('NNET');
}

// PRIO 2: HOCH
if (isEnabled('matrix3_nina_warnung')) {
    var nina = parseInt(getState('sensor.nina_munchen_warnungen_anzahl')) || 0;
    if (nina > 0) {
        var txt = getState('sensor.nina_munchen_warnung_aktuell') || 'NINA';
        alerts.push(txt.substring(0, 4));
    }
}
if (isEnabled('matrix3_dwd_wetter')) {
    var dwd = parseInt(getState('sensor.dwd_munchen_warnungen')) || 0;
    if (dwd > 0) alerts.push('UNWT');
}
if (isEnabled('matrix3_hochwasser')) {
    var pegel = parseFloat(getState('sensor.pegel_isar_muenchen')) || 0;
    if (pegel > 600) alerts.push('HCHW');
}
if (isEnabled('matrix3_thw_rueckmeldung') && isOn('binary_sensor.divera_ruckmeldung_fallig')) {
    alerts.push('THW!');
}
if (isEnabled('matrix3_netzwerk')) {
    var netz = getState('sensor.netzwerk_status');
    if (netz && netz !== 'Alles OK' && netz !== 'unknown' && netz !== 'unavailable') {
        alerts.push('NETZ');
    }
}

// PRIO 3: MITTEL
if (isEnabled('matrix3_petkit')) {
    var petkit = getState('sensor.petkit_status');
    if (petkit && petkit !== 'ok' && petkit !== 'unknown' && petkit !== 'unavailable') {
        alerts.push('KATZ');
    }
}
if (isEnabled('matrix3_meshtastic')) {
    var lastMsg = getState('sensor.mesh_letzte_nachricht');
    var lastTime = getState('sensor.mesh_letzte_nachricht_zeit');
    if (lastMsg && lastTime) {
        var msgAge = (Date.now() - new Date(lastTime).getTime()) / 60000;
        if (msgAge < 30 && msgAge >= 0) {
            alerts.push('MESH');
        }
    }
}
if (isEnabled('matrix3_mesh_batterie')) {
    var bats = ['mesh_gw_battery','mesh_supreme_battery','mesh_deck_battery','mesh_otn_battery'];
    for (var i = 0; i < bats.length; i++) {
        var bat = parseFloat(getState('sensor.' + bats[i])) || 100;
        if (bat < 20 && bat > 0) {
            alerts.push('B' + Math.round(bat));
            break;
        }
    }
}
if (isEnabled('matrix3_waschmaschine') && isOn('input_boolean.waschmaschine_warten')) {
    alerts.push('WSCH');
}
if (isEnabled('matrix3_trockner') && isOn('input_boolean.trockner_warten')) {
    alerts.push('TRCK');
}

// PRIO 4: NIEDRIG
if (isEnabled('matrix3_tibber_teuer')) {
    var price = getState('sensor.tibber_price_level');
    if (price === 'VERY_EXPENSIVE') alerts.push('TEUR');
}
if (isEnabled('matrix3_tibber_guenstig')) {
    var price2 = getState('sensor.tibber_price_level');
    if (price2 === 'VERY_CHEAP') alerts.push('BIL!');
}

flow.set('m3_alerts', alerts);
return msg;

var watts = flow.get('m3_pv_watts') || 0;
var dailyKwh = flow.get('m3_daily_kwh') || 0;
var yesterdayKwh = flow.get('m3_yesterday_kwh') || 0;
var flashUntil = flow.get('m3_show_pv_until') || 0;
var now = Date.now();
var left = '';

// === LINKE HAELFTE: Uhr / PV (max 5 Zeichen) ===
if (now < flashUntil) {
    if (watts >= 15) {
        left = Math.round(watts) + 'W';
    } else {
        var kwh = (dailyKwh < 0.05 && yesterdayKwh > 0.05) ? yesterdayKwh : dailyKwh;
        left = kwh.toFixed(1) + 'kW';
    }
} else {
    var d = new Date();
    var h = String(d.getHours()).padStart(2, '0');
    var m = String(d.getMinutes()).padStart(2, '0');
    var sep = (d.getSeconds() % 2 === 0) ? ':' : ' ';
    left = h + sep + m;
}

// Links auf 5 Zeichen padden
while (left.length < 5) left = left + ' ';

// === RECHTE HAELFTE: Benachrichtigungen (max 4 Zeichen) ===
var alerts = flow.get('m3_alerts') || [];
var right = '';
if (alerts.length > 0) {
    var idx = Math.floor(Date.now() / 3000) % alerts.length;
    right = alerts[idx].substring(0, 4);
}

// Kombinieren: links(5) + Leerzeichen + rechts(max 4) = max 10 Zeichen
if (right) {
    msg.payload = left + ' ' + right;
} else {
    msg.payload = left;
}
return msg;

var h = new Date().getHours();
msg.payload = (h >= 22 || h < 7) ? 1 : 5;
return msg;
